"""
Instant Hook Recognition Engine
Builds on original simple hook-based system for instant context recognition
Integrates with MVCO and optimization engines for learning-based hook expansion
"""

import re
import json
import time
import asyncio
from typing import Dict, List, Optional, Tuple, Any, Callable, Pattern
from dataclasses import dataclass, asdict
from enum import Enum
from collections import defaultdict, deque
import pickle
from pathlib import Path

class HookType(Enum):
    """Types of instant recognition hooks"""
    NUMERIC = "numeric"           # Math, calculations, numbers
    COMMAND = "command"           # Direct commands, actions
    LIST = "list"                 # List requests, enumeration
    PLAN = "plan"                 # Planning, steps, workflow
    QUERY = "query"               # Simple questions
    GREETING = "greeting"         # Social interactions
    STATUS = "status"             # System status requests
    CONFIRMATION = "confirmation" # Yes/no, confirmations
    LEARNED = "learned"           # Patterns learned through use

@dataclass
class InstantHook:
    """Single instant recognition hook"""
    hook_id: str
    hook_type: HookType
    pattern: Pattern[str]
    response_template: str
    confidence: float
    usage_count: int = 0
    success_rate: float = 1.0
    last_used: float = 0.0
    learned: bool = False
    priority: int = 1  # 1 = highest priority

@dataclass
class HookMatch:
    """Result of hook matching"""
    hook: InstantHook
    match_groups: List[str]
    confidence: float
    instant_response: str

class InstantHookEngine:
    """Engine for instant recognition using hook-based patterns"""

    def __init__(self, config_path: Optional[str] = None):
        self.config_path = config_path or "instant_hooks.json"

        # Core hook registry
        self.hooks: Dict[str, InstantHook] = {}
        self.hook_categories: Dict[HookType, List[str]] = defaultdict(list)

        # Learning system
        self.usage_history = deque(maxlen=1000)
        self.learning_enabled = True
        self.min_pattern_frequency = 3  # Minimum occurrences to create learned hook

        # Performance tracking
        self.instant_response_count = 0
        self.total_query_count = 0

        # Initialize base hooks
        self._initialize_base_hooks()

        # Load learned hooks if available
        self._load_learned_hooks()

    def _initialize_base_hooks(self):
        """Initialize the foundational instant recognition hooks"""

        # NUMERIC hooks - Math, calculations, numbers
        numeric_hooks = [
            ("simple_math", r"^(\d+)\s*([+\-*/])\s*(\d+)$", self._handle_simple_math, 1.0),
            ("number_query", r"^what\s+is\s+(\d+)\s*([+\-*/])\s*(\d+)\??$", self._handle_simple_math, 0.95),
            ("percentage", r"^(\d+)%\s+of\s+(\d+)$", self._handle_percentage, 0.9),
            ("prime_check", r"^is\s+(\d+)\s+prime\??$", self._handle_prime_check, 0.85),
            ("factor_check", r"^factors?\s+of\s+(\d+)$", self._handle_factors, 0.8),
        ]

        # COMMAND hooks - Direct actions
        command_hooks = [
            ("help_command", r"^/?(help|h)\s*$", lambda m: "Available commands: /help, /mode, /model, /config, /status", 1.0),
            ("status_command", r"^/?(status|stat)\s*$", lambda m: "System operational - Quality Recovery Engine active", 1.0),
            ("version_command", r"^/?(version|ver|v)\s*$", lambda m: "OpenCode v1.0 with Instant Hook Engine", 1.0),
            ("clear_command", r"^/?(clear|cls)\s*$", lambda m: "Screen cleared", 1.0),
            ("exit_command", r"^/?(exit|quit|q)\s*$", lambda m: "Goodbye!", 1.0),
        ]

        # LIST hooks - Enumeration, listing
        list_hooks = [
            ("list_files", r"^(ls|list|dir)\s*$", lambda m: "📁 Use `ls` in terminal or `/files` for file listing", 0.95),
            ("show_models", r"^(list|show)\s+(models?|llms?)\s*$", lambda m: "🤖 Available models: Use `/model` to see current model", 0.9),
            ("list_commands", r"^(list|show)\s+(commands?|help)\s*$", lambda m: "📋 Commands: /help, /mode, /model, /config, /status", 0.9),
            ("enumerate_items", r"^(list|enumerate|show)\s+(.+)$", self._handle_generic_list, 0.7),
        ]

        # PLAN hooks - Planning, workflow, steps
        plan_hooks = [
            ("simple_plan", r"^(plan|steps?)\s+to\s+(.+)$", self._handle_simple_plan, 0.8),
            ("how_to", r"^how\s+to\s+(.+)\??$", self._handle_how_to, 0.75),
            ("workflow", r"^workflow\s+for\s+(.+)$", self._handle_workflow, 0.7),
            ("process", r"^(process|procedure)\s+for\s+(.+)$", self._handle_process, 0.7),
        ]

        # QUERY hooks - Simple questions
        query_hooks = [
            ("what_is", r"^what\s+is\s+([a-zA-Z]\w*)\??$", self._handle_what_is, 0.8),
            ("when_is", r"^when\s+is\s+(.+)\??$", self._handle_when_is, 0.7),
            ("where_is", r"^where\s+is\s+(.+)\??$", self._handle_where_is, 0.7),
            ("who_is", r"^who\s+is\s+(.+)\??$", self._handle_who_is, 0.7),
            ("why_is", r"^why\s+is\s+(.+)\??$", self._handle_why_is, 0.6),
        ]

        # GREETING hooks
        greeting_hooks = [
            ("hello", r"^(hi|hello|hey)\s*!?$", lambda m: "Hello! How can I help you?", 1.0),
            ("goodbye", r"^(bye|goodbye|see\s+you)\s*!?$", lambda m: "Goodbye! Have a great day!", 1.0),
            ("thanks", r"^(thanks?|thank\s+you)\s*!?$", lambda m: "You're welcome!", 1.0),
            ("good_morning", r"^good\s+(morning|afternoon|evening)\s*!?$", self._handle_time_greeting, 0.9),
        ]

        # STATUS hooks - System information
        status_hooks = [
            ("ready", r"^(ready|online|up)\??$", lambda m: "Yes, I'm ready to help!", 1.0),
            ("working", r"^(working|functioning)\??$", lambda m: "Yes, all systems operational!", 1.0),
            ("current_mode", r"^(current\s+)?(mode|setting)$", lambda m: "Current mode: Auto (Quality Recovery Active)", 0.9),
        ]

        # CONFIRMATION hooks
        confirmation_hooks = [
            ("yes", r"^(yes|y|yep|yeah|correct|right)\s*!?$", lambda m: "Understood.", 1.0),
            ("no", r"^(no|n|nope|incorrect|wrong)\s*!?$", lambda m: "Okay, noted.", 1.0),
            ("ok", r"^(ok|okay|alright|fine)\s*!?$", lambda m: "Great!", 1.0),
        ]

        # Register all hooks
        all_hook_groups = [
            (HookType.NUMERIC, numeric_hooks),
            (HookType.COMMAND, command_hooks),
            (HookType.LIST, list_hooks),
            (HookType.PLAN, plan_hooks),
            (HookType.QUERY, query_hooks),
            (HookType.GREETING, greeting_hooks),
            (HookType.STATUS, status_hooks),
            (HookType.CONFIRMATION, confirmation_hooks),
        ]

        for hook_type, hooks in all_hook_groups:
            for hook_id, pattern, response_func, confidence in hooks:
                self._register_hook(hook_id, hook_type, pattern, response_func, confidence)

    def _register_hook(self, hook_id: str, hook_type: HookType, pattern: str,
                      response_func: Callable, confidence: float, learned: bool = False):
        """Register a new instant hook"""

        compiled_pattern = re.compile(pattern, re.IGNORECASE)

        # Convert response function to template if it's a simple string
        if isinstance(response_func, str):
            response_template = response_func
        else:
            response_template = response_func  # Store the function directly

        hook = InstantHook(
            hook_id=hook_id,
            hook_type=hook_type,
            pattern=compiled_pattern,
            response_template=response_template,
            confidence=confidence,
            learned=learned
        )

        self.hooks[hook_id] = hook
        self.hook_categories[hook_type].append(hook_id)

    def recognize_instant_pattern(self, user_input: str) -> Optional[HookMatch]:
        """Attempt to recognize instant pattern and generate immediate response"""

        self.total_query_count += 1
        text = user_input.strip()

        # Try hooks in priority order (highest confidence first)
        sorted_hooks = sorted(self.hooks.values(),
                            key=lambda h: (h.priority, h.confidence, h.success_rate),
                            reverse=True)

        for hook in sorted_hooks:
            match = hook.pattern.match(text)
            if match:
                # Generate instant response
                try:
                    if callable(hook.response_template):
                        response = hook.response_template(match)
                    else:
                        # Simple string template
                        response = hook.response_template

                    # Update hook statistics
                    hook.usage_count += 1
                    hook.last_used = time.time()

                    # Create match result
                    hook_match = HookMatch(
                        hook=hook,
                        match_groups=list(match.groups()),
                        confidence=hook.confidence,
                        instant_response=response
                    )

                    self.instant_response_count += 1
                    self._record_successful_match(hook, user_input, response)

                    return hook_match

                except Exception as e:
                    print(f"Hook {hook.hook_id} failed: {e}")
                    hook.success_rate *= 0.95  # Slightly reduce success rate
                    continue

        # No hook matched - record for potential learning
        self._record_unmatched_input(user_input)
        return None

    def _handle_simple_math(self, match) -> str:
        """Handle simple mathematical expressions"""
        try:
            if len(match.groups()) == 3:
                # Pattern: number operator number
                a, op, b = match.groups()
                a, b = float(a), float(b)
            elif len(match.groups()) == 2:
                # Alternative pattern: "what is X + Y"
                expr = match.groups()[1]
                # Parse expression
                math_match = re.match(r'(\d+)\s*([+\-*/])\s*(\d+)', expr)
                if math_match:
                    a, op, b = math_match.groups()
                    a, b = float(a), float(b)
                else:
                    return "I can help with simple math like: 2+2, 10*5, 20/4"

            # Calculate result
            if op == '+':
                result = a + b
            elif op == '-':
                result = a - b
            elif op == '*':
                result = a * b
            elif op == '/' and b != 0:
                result = a / b
            else:
                return "Cannot divide by zero"

            # Format result
            if result == int(result):
                return str(int(result))
            else:
                return f"{result:.2f}"

        except (ValueError, IndexError):
            return "I can help with simple math like: 2+2, 10*5, 20/4"

    def _handle_percentage(self, match) -> str:
        """Handle percentage calculations"""
        try:
            percent, total = match.groups()
            result = (float(percent) / 100) * float(total)
            return f"{result:.2f}"
        except ValueError:
            return "Please use format: 25% of 100"

    def _handle_prime_check(self, match) -> str:
        """Check if a number is prime"""
        try:
            n = int(match.groups()[0])
            if n < 2:
                return "No"
            for i in range(2, int(n ** 0.5) + 1):
                if n % i == 0:
                    return "No"
            return "Yes"
        except ValueError:
            return "Please provide a valid number"

    def _handle_factors(self, match) -> str:
        """Find factors of a number"""
        try:
            n = int(match.groups()[0])
            factors = [i for i in range(1, n + 1) if n % i == 0]
            return f"Factors of {n}: {', '.join(map(str, factors))}"
        except ValueError:
            return "Please provide a valid number"

    def _handle_generic_list(self, match) -> str:
        """Handle generic list requests"""
        item = match.groups()[1] if match.groups() else "items"
        return f"📋 To list {item}, please provide more specific context or use appropriate commands."

    def _handle_simple_plan(self, match) -> str:
        """Handle simple planning requests"""
        task = match.groups()[1] if match.groups() else "the task"
        return f"📝 Basic steps for {task}:\n1. Define requirements\n2. Plan approach\n3. Execute\n4. Review results"

    def _handle_how_to(self, match) -> str:
        """Handle how-to questions"""
        task = match.groups()[0] if match.groups() else "accomplish this"
        return f"💡 To {task}:\n1. Research the topic\n2. Gather necessary resources\n3. Follow best practices\n4. Test and refine"

    def _handle_workflow(self, match) -> str:
        """Handle workflow requests"""
        process = match.groups()[0] if match.groups() else "the process"
        return f"⚡ Workflow for {process}:\n• Analysis phase\n• Implementation phase\n• Testing phase\n• Deployment phase"

    def _handle_process(self, match) -> str:
        """Handle process requests"""
        task = match.groups()[0] if match.groups() else "the task"
        return f"🔄 Process for {task}:\n1. Planning\n2. Execution\n3. Monitoring\n4. Optimization"

    def _handle_what_is(self, match) -> str:
        """Handle 'what is' questions"""
        term = match.groups()[0] if match.groups() else "term"
        # Simple definitions for common terms
        definitions = {
            "python": "Python is a high-level programming language known for simplicity and readability.",
            "ai": "AI (Artificial Intelligence) refers to computer systems that can perform tasks typically requiring human intelligence.",
            "api": "API (Application Programming Interface) is a set of protocols for building software applications.",
            "git": "Git is a distributed version control system for tracking changes in source code.",
            "json": "JSON (JavaScript Object Notation) is a lightweight data interchange format.",
        }

        definition = definitions.get(term.lower())
        if definition:
            return definition
        else:
            return f"'{term}' is a concept that would benefit from more detailed explanation. Use standard mode for comprehensive information."

    def _handle_when_is(self, match) -> str:
        """Handle 'when is' questions"""
        event = match.groups()[0] if match.groups() else "event"
        return f"⏰ For timing information about '{event}', I'd need more context or real-time data access."

    def _handle_where_is(self, match) -> str:
        """Handle 'where is' questions"""
        item = match.groups()[0] if match.groups() else "item"
        return f"📍 Location queries for '{item}' require more context or access to current data."

    def _handle_who_is(self, match) -> str:
        """Handle 'who is' questions"""
        person = match.groups()[0] if match.groups() else "person"
        return f"👤 Information about '{person}' would benefit from more detailed research. Try standard mode."

    def _handle_why_is(self, match) -> str:
        """Handle 'why is' questions"""
        topic = match.groups()[0] if match.groups() else "topic"
        return f"🤔 The reasoning behind '{topic}' likely requires detailed analysis. Consider using think mode."

    def _handle_time_greeting(self, match) -> str:
        """Handle time-based greetings"""
        time_of_day = match.groups()[0] if match.groups() else "day"
        responses = {
            "morning": "Good morning! Ready to tackle the day?",
            "afternoon": "Good afternoon! How can I assist you?",
            "evening": "Good evening! What can I help you with?"
        }
        return responses.get(time_of_day, "Hello! How can I help you?")

    def _record_successful_match(self, hook: InstantHook, input_text: str, response: str):
        """Record successful hook match for learning"""
        self.usage_history.append({
            'timestamp': time.time(),
            'hook_id': hook.hook_id,
            'hook_type': hook.hook_type.value,
            'input': input_text,
            'response': response,
            'success': True
        })

    def _record_unmatched_input(self, input_text: str):
        """Record input that didn't match any hook for potential learning"""
        self.usage_history.append({
            'timestamp': time.time(),
            'hook_id': None,
            'hook_type': 'unmatched',
            'input': input_text,
            'response': None,
            'success': False
        })

    def learn_new_patterns(self) -> int:
        """Analyze usage history to learn new instant response patterns"""
        if not self.learning_enabled:
            return 0

        # Find frequently unmatched patterns
        unmatched_inputs = [entry for entry in self.usage_history
                          if not entry['success']]

        # Group similar inputs
        pattern_candidates = defaultdict(list)
        for entry in unmatched_inputs:
            # Simple pattern detection - look for repeated structures
            simplified = self._simplify_for_pattern_detection(entry['input'])
            pattern_candidates[simplified].append(entry['input'])

        # Create new hooks for frequently occurring patterns
        new_hooks = 0
        for simplified_pattern, examples in pattern_candidates.items():
            if len(examples) >= self.min_pattern_frequency:
                hook_id = f"learned_{len(self.hooks)}"
                pattern = self._create_pattern_from_examples(examples)
                if pattern:
                    self._register_hook(
                        hook_id,
                        HookType.LEARNED,
                        pattern,
                        self._generate_learned_response,
                        confidence=0.6,  # Lower confidence for learned patterns
                        learned=True
                    )
                    new_hooks += 1

        return new_hooks

    def _simplify_for_pattern_detection(self, text: str) -> str:
        """Simplify text to detect patterns"""
        # Replace numbers with placeholder
        text = re.sub(r'\d+', 'NUM', text.lower())
        # Replace common variable parts
        text = re.sub(r'[a-z]+', 'WORD', text)
        return text.strip()

    def _create_pattern_from_examples(self, examples: List[str]) -> Optional[str]:
        """Create regex pattern from example inputs"""
        if len(examples) < 2:
            return None

        # Very simple pattern creation - would need more sophistication
        # For now, just create patterns for similar structure
        first = examples[0].lower()

        # Create basic pattern
        pattern = re.escape(first)
        pattern = re.sub(r'\\d+', r'(\\d+)', pattern)  # Numbers
        pattern = re.sub(r'[a-z]+', r'([a-z]+)', pattern)  # Words

        return f"^{pattern}$"

    def _generate_learned_response(self, match) -> str:
        """Generate response for learned patterns"""
        return f"I've learned to recognize this pattern. Processing with standard intelligence..."

    def get_instant_coverage_stats(self) -> Dict[str, Any]:
        """Get statistics on instant response coverage"""
        total_queries = max(1, self.total_query_count)
        instant_rate = self.instant_response_count / total_queries

        # Hook type distribution
        type_usage = defaultdict(int)
        for hook in self.hooks.values():
            type_usage[hook.hook_type.value] += hook.usage_count

        return {
            'total_queries': total_queries,
            'instant_responses': self.instant_response_count,
            'instant_rate': round(instant_rate, 3),
            'hook_count': len(self.hooks),
            'hook_types': dict(type_usage),
            'most_used_hooks': [
                (hook.hook_id, hook.usage_count)
                for hook in sorted(self.hooks.values(),
                                 key=lambda h: h.usage_count, reverse=True)[:5]
            ]
        }

    def _save_learned_hooks(self):
        """Save learned hooks to disk"""
        try:
            learned_hooks = {
                hook_id: {
                    'hook_type': hook.hook_type.value,
                    'pattern': hook.pattern.pattern,
                    'confidence': hook.confidence,
                    'usage_count': hook.usage_count,
                    'success_rate': hook.success_rate
                }
                for hook_id, hook in self.hooks.items()
                if hook.learned
            }

            with open(self.config_path, 'w') as f:
                json.dump(learned_hooks, f, indent=2)
        except Exception as e:
            print(f"Failed to save learned hooks: {e}")

    def _load_learned_hooks(self):
        """Load previously learned hooks"""
        try:
            if Path(self.config_path).exists():
                with open(self.config_path, 'r') as f:
                    learned_hooks = json.load(f)

                for hook_id, hook_data in learned_hooks.items():
                    self._register_hook(
                        hook_id,
                        HookType(hook_data['hook_type']),
                        hook_data['pattern'],
                        self._generate_learned_response,
                        hook_data['confidence'],
                        learned=True
                    )

                    # Restore usage statistics
                    if hook_id in self.hooks:
                        self.hooks[hook_id].usage_count = hook_data.get('usage_count', 0)
                        self.hooks[hook_id].success_rate = hook_data.get('success_rate', 1.0)
        except Exception as e:
            print(f"Failed to load learned hooks: {e}")


# Testing function
async def test_instant_hooks():
    """Test the instant hook engine"""

    print("🧪 Testing Instant Hook Engine\n")

    # Initialize engine
    hook_engine = InstantHookEngine()

    # Test cases covering all hook types
    test_cases = [
        # NUMERIC
        ("2+2", "Basic math"),
        ("what is 15 * 3", "Math question"),
        ("25% of 200", "Percentage calculation"),
        ("is 17 prime", "Prime check"),

        # COMMAND
        ("/help", "Help command"),
        ("status", "Status check"),
        ("version", "Version info"),

        # LIST
        ("ls", "List files"),
        ("list models", "Show models"),

        # PLAN
        ("plan to learn Python", "Simple planning"),
        ("how to code", "How-to question"),

        # QUERY
        ("what is Python", "Definition question"),
        ("when is Christmas", "Time question"),

        # GREETING
        ("hi", "Simple greeting"),
        ("good morning", "Time greeting"),
        ("thanks", "Appreciation"),

        # CONFIRMATION
        ("yes", "Confirmation"),
        ("ok", "Agreement"),

        # Unmatched (should not trigger instant response)
        ("This is a complex query that requires deep analysis and multiple steps to complete properly", "Complex input")
    ]

    print("📊 Hook Recognition Results:")
    print("-" * 80)

    instant_count = 0
    for input_text, description in test_cases:
        hook_match = hook_engine.recognize_instant_pattern(input_text)

        if hook_match:
            instant_count += 1
            print(f"✅ INSTANT: {input_text}")
            print(f"   Hook: {hook_match.hook.hook_id} ({hook_match.hook.hook_type.value})")
            print(f"   Confidence: {hook_match.confidence:.2f}")
            print(f"   Response: {hook_match.instant_response}")
        else:
            print(f"❌ No Match: {input_text}")
            print(f"   → Falls back to standard processing")

        print(f"   Description: {description}")
        print("-" * 80)

    # Display coverage statistics
    print(f"\n📈 Coverage Statistics:")
    stats = hook_engine.get_instant_coverage_stats()
    print(f"Total Queries: {stats['total_queries']}")
    print(f"Instant Responses: {stats['instant_responses']}")
    print(f"Instant Rate: {stats['instant_rate'] * 100:.1f}%")
    print(f"Hook Count: {stats['hook_count']}")

    print(f"\n🏆 Most Used Hooks:")
    for hook_id, count in stats['most_used_hooks']:
        if count > 0:
            print(f"   {hook_id}: {count} uses")

    # Test learning capability
    print(f"\n🧠 Learning Test:")
    new_hooks = hook_engine.learn_new_patterns()
    print(f"New patterns learned: {new_hooks}")


if __name__ == "__main__":
    asyncio.run(test_instant_hooks())